import React, { useState } from "react";
import Hamburger from "hamburger-react";
import { NavLink } from "react-router-dom";
const HamburgerMenu = () => {
  const [isOpen, setOpen] = useState(false);

  const navLinks = [
    { to: '/', labe: "Home" },
    { to: '/products', labe: "Shop" },
    { to: '/cart', labe: "Cart" },
    { to: '/login', labe: "Log In" },
    { to: '/register', labe: "Join Now", special: true }
  ]

  const NavItems = ({ isMobile }) => {
    <ul className={`${isMobile ? "flex flex-col space-y-4" : "flex items-center space-x-6"
      } text-lg font-semibold text-gray-700`}>
      navLinks.map(({to, label, special}) => (
      <li key={to}>
        <NavLink to={to}
          className={({ isActive }) =>
            isActive
              ? special
                ? "bg-blue-700 text-white px-4 py-2 rounded-lg"
                : "text-blue-600 border-b-2 border-blue-600 pb-1"
              : special
                ? "bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition duration-300"
                : "hover:text-blue-600 transition duration-300"
          }>
          {label}
        </NavLink>
      </li>
      ))
    </ul>
  }
  return (
    <div>
      <div className="md:hidden">
        <Hamburger toggled={isOpen} toggle={setOpen} />
        {isOpen && <NavItems isMobile />}
      </div>

      <nav className="hidden md:block">
        <div className="container mx-auto px-6 py-4">
          <NavItems />
        </div>
      </nav>
    </div>
  );
};
export default HamburgerMenu;
